import{c as i,Z as o,Q as l,j as e,o as r,m as d}from"./chunks/framework.qjzPVSkb.js";const f=JSON.parse('{"title":"GitHub Copilot","description":"Microsoft 出品——VS Code 最强 AI 代码补全插件，免费版开放","frontmatter":{"title":"GitHub Copilot","description":"Microsoft 出品——VS Code 最强 AI 代码补全插件，免费版开放","difficulty":"intermediate"},"headers":[],"relativePath":"tools/copilot.md","filePath":"tools/copilot.md"}'),n={name:"tools/copilot.md"};function h(s,t,u,c,p,b){const a=o("DifficultyBadge");return l(),e("div",null,[r(a,{level:"intermediate"}),t[0]||(t[0]=d('<h1 id="github-copilot" tabindex="-1">GitHub Copilot <a class="header-anchor" href="#github-copilot" aria-label="Permalink to &quot;GitHub Copilot&quot;">​</a></h1><h2 id="一句话定位" tabindex="-1">一句话定位 <a class="header-anchor" href="#一句话定位" aria-label="Permalink to &quot;一句话定位&quot;">​</a></h2><p><strong>最流行的 AI 编程插件</strong>——深度集成 VS Code 和 JetBrains，代码补全流畅自然，是 AI 编程的&quot;默认选项&quot;。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项目</th><th>详情</th></tr></thead><tbody><tr><td>公司</td><td>GitHub (Microsoft)</td></tr><tr><td>价格</td><td>免费版 / Individual $10/月 / Business $19/人/月</td></tr><tr><td>支持模型</td><td>GPT-4o / Claude 3.5 Sonnet / o1 等</td></tr><tr><td>平台</td><td>VS Code / JetBrains / Visual Studio / Neovim 等</td></tr><tr><td>首发时间</td><td>2021 年 6 月</td></tr></tbody></table><h2 id="核心功能" tabindex="-1">核心功能 <a class="header-anchor" href="#核心功能" aria-label="Permalink to &quot;核心功能&quot;">​</a></h2><h3 id="⌨️-代码补全" tabindex="-1">⌨️ 代码补全 <a class="header-anchor" href="#⌨️-代码补全" aria-label="Permalink to &quot;⌨️ 代码补全&quot;">​</a></h3><p>Copilot 最经典的功能。在你敲代码时，它会：</p><ul><li>给出灰色的补全建议</li><li>按 Tab 接受，按 Esc 忽略</li><li>理解上下文（函数名、变量、注释）给出准确建议</li></ul><p>补全范围从一行到整个函数，准确率很高。</p><h3 id="💬-copilot-chat" tabindex="-1">💬 Copilot Chat <a class="header-anchor" href="#💬-copilot-chat" aria-label="Permalink to &quot;💬 Copilot Chat&quot;">​</a></h3><p>侧边栏对话，功能类似 Cursor Chat：</p><ul><li>选中代码提问</li><li>生成单元测试</li><li>解释代码逻辑</li><li>修复 Bug</li></ul><h3 id="✏️-内联编辑-inline-chat" tabindex="-1">✏️ 内联编辑（Inline Chat） <a class="header-anchor" href="#✏️-内联编辑-inline-chat" aria-label="Permalink to &quot;✏️ 内联编辑（Inline Chat）&quot;">​</a></h3><p>在代码中直接输入指令，Copilot 在原地修改代码。类似 Cursor 的 <code>Ctrl+K</code>。</p><h3 id="🗣️-语音编程" tabindex="-1">🗣️ 语音编程 <a class="header-anchor" href="#🗣️-语音编程" aria-label="Permalink to &quot;🗣️ 语音编程&quot;">​</a></h3><p>支持语音输入（VS Code 插件），说出你要实现的功能，Copilot 帮你写代码。</p><h3 id="📚-代码审查" tabindex="-1">📚 代码审查 <a class="header-anchor" href="#📚-代码审查" aria-label="Permalink to &quot;📚 代码审查&quot;">​</a></h3><p>通过 <code>/review</code> 命令，让 Copilot 帮你审查代码，发现潜在问题。</p><h2 id="优势" tabindex="-1">优势 <a class="header-anchor" href="#优势" aria-label="Permalink to &quot;优势&quot;">​</a></h2><ul><li><strong>有免费版</strong>：对于轻度用户来说完全够用</li><li><strong>IDE 兼容性广</strong>：支持 VS Code、JetBrains、Visual Studio、Neovim 等</li><li><strong>模型选择多</strong>：可以切换 GPT-4o、Claude 3.5 Sonnet、o1 等模型</li><li><strong>与 GitHub 深度集成</strong>：与 GitHub Issues、PR、Actions 等联动</li><li><strong>成熟稳定</strong>：最早上线的 AI 编程工具之一，可靠性高</li></ul><h2 id="不足" tabindex="-1">不足 <a class="header-anchor" href="#不足" aria-label="Permalink to &quot;不足&quot;">​</a></h2><ul><li>插件形式，不如 Cursor/Windsurf 那种原生 IDE 体验深入</li><li>多文件编辑能力不如 Composer/Cascade</li><li>免费版有使用限制（2000 次补全 + 50 次 Chat / 月）</li><li>没有项目级上下文管理（不能像 Cursor 那样 @ 标记文件）</li></ul><h2 id="适合谁" tabindex="-1">适合谁？ <a class="header-anchor" href="#适合谁" aria-label="Permalink to &quot;适合谁？&quot;">​</a></h2><ul><li>✅ VS Code / JetBrains 用户，不想换 IDE</li><li>✅ 轻度使用者（免费版够用）</li><li>✅ 已有成熟开发环境的团队</li><li>✅ 需要多 IDE 支持的用户</li><li>⚠️ 需要深度 AI 辅助（多文件重构等）建议选 Cursor 或 Windsurf</li></ul><h2 id="快速上手" tabindex="-1">快速上手 <a class="header-anchor" href="#快速上手" aria-label="Permalink to &quot;快速上手&quot;">​</a></h2><ol><li>在 VS Code 扩展商店搜索 &quot;GitHub Copilot&quot;</li><li>安装并登录 GitHub 账号</li><li>打开任意代码文件，开始编码</li><li>灰色建议出现后按 Tab 接受</li><li>按 <code>Ctrl+I</code>（Mac: <code>Cmd+I</code>）打开内联编辑</li><li>按 <code>Ctrl+Shift+I</code>（Mac: <code>Cmd+Shift+I</code>）打开 Chat</li></ol><h2 id="关联阅读" tabindex="-1">关联阅读 <a class="header-anchor" href="#关联阅读" aria-label="Permalink to &quot;关联阅读&quot;">​</a></h2><ul><li><a href="/ai-knowledge/tools/cursor.html">Cursor</a> —— AI IDE 版本，AI 体验更深</li><li><a href="/ai-knowledge/tools/windsurf.html">Windsurf</a> —— 另一款 AI IDE</li><li><a href="/ai-knowledge/tools/opencode.html">OpenCode</a> —— 开源替代方案</li></ul>',29))])}const m=i(n,[["render",h]]);export{f as __pageData,m as default};
